#!/usr/bin/env bash
set -u

IR_TIMEOUT="${IR_TIMEOUT:-30}"
ASM_TIMEOUT="${ASM_TIMEOUT:-30}"

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
SYSY="${ROOT_DIR}/bin/compiler"
LIBDIR="${ROOT_DIR}/lib"
OPTC_BIN="${ROOT_DIR}/optc"
OPTDIR="${ROOT_DIR}/optcases"

RED=$'\033[91m'
YELLOW=$'\033[93m'
GREEN=$'\033[92m'
NC=$'\033[0m'

add_returncode() {
  local f="$1"
  local rc="$2"
  if [[ -f "$f" && -s "$f" ]]; then
    local last_hex
    last_hex="$(tail -c 1 "$f" 2>/dev/null | od -An -tx1 2>/dev/null | tr -d ' \n' || true)"
    if [[ "$last_hex" != "0a" ]]; then
      printf '\n' >>"$f"
    fi
  fi
  printf '%s\n' "$rc" >>"$f"
}

_extract_section_b64_to_file() {
  # $1: start_marker, $2: end_marker, $3: output_file
  local start_marker="$1"
  local end_marker="$2"
  local out_file="$3"

  local start_line end_line
  start_line="$(awk -v m="^${start_marker}$" '$0 ~ m {print NR + 1; exit 0}' "$0")"
  end_line="$(awk -v m="^${end_marker}$" '$0 ~ m {print NR - 1; exit 0}' "$0")"

  if [[ -z "$start_line" || -z "$end_line" || "$end_line" -lt "$start_line" ]]; then
    echo "ERROR: payload markers not found or invalid: $start_marker .. $end_marker" >&2
    return 2
  fi

  sed -n "${start_line},${end_line}p" "$0" | base64 -d >"$out_file"
}

extract_optc() {
  rm -f "$OPTC_BIN" 2>/dev/null || true
  _extract_section_b64_to_file "__OPTC_B64_BELOW__" "__ARCHIVE_B64_BELOW__" "$OPTC_BIN" || return $?
  chmod +x "$OPTC_BIN" 2>/dev/null || true
}

extract_optcases() {
  if [[ -d "$OPTDIR" ]]; then
    rm -rf "$OPTDIR"
  fi

  local tmp_tgz
  tmp_tgz="$(mktemp 2>/dev/null || mktemp -t optcases_tgz)"

  local start_line
  start_line="$(awk '/^__ARCHIVE_B64_BELOW__$/ {print NR + 1; exit 0;}' "$0")"
  if [[ -z "$start_line" ]]; then
    echo "ERROR: archive marker not found" >&2
    rm -f "$tmp_tgz"
    return 2
  fi

  tail -n "+$start_line" "$0" | base64 -d >"$tmp_tgz"
  tar -xzm -f "$tmp_tgz"
  local ec=$?
  rm -f "$tmp_tgz"
  return $ec
}

gen_check_file() {
  local ll="$1"
  local ck="$2"
  "$OPTC_BIN" -check --check=all "$ll" >"$ck"
}

run_one_case() {
  local case_dir="$1"
  local name
  name="$(basename "$case_dir")"

  local src="${case_dir}/test.sy"
  local stdin_file="${case_dir}/test.in"
  local std_out="${case_dir}/test.out"
  local out_ll="${case_dir}/test.ll"
  local act_out="${case_dir}/real.out"

  if [[ ! -f "$src" || ! -f "$std_out" ]]; then
    return 2
  fi

  local tmpdir
  tmpdir="$(mktemp -d 2>/dev/null || mktemp -d -t sysyopt)"
  local tmp_o="${tmpdir}/tmp.o"
  local tmp_bin="${tmpdir}/tmp.bin"

  if ! timeout "$IR_TIMEOUT" "$SYSY" "$src" -llvm -o "$out_ll" -O1 >/dev/null 2>/dev/null; then
    local ec=$?
    rm -rf "$tmpdir"
    if [[ $ec -eq 124 ]]; then
      printf '%s  %sCompile Time Limit Exceed%s\n' "$name" "$YELLOW" "$NC"
    else
      printf '%s  %sCompiler Error%s\n' "$name" "$YELLOW" "$NC"
    fi
    return 1
  fi

  if ! llvm-as "$out_ll" -o /dev/null >/dev/null 2>/dev/null; then
    rm -rf "$tmpdir"
    printf '%s  %sLLVM-IR Syntax Error%s\n' "$name" "$YELLOW" "$NC"
    return 1
  fi

  gen_check_file "$out_ll" "${case_dir}/test.ck" || true

  if ! clang "$out_ll" -c -o "$tmp_o" -w >/dev/null 2>/dev/null; then
    rm -rf "$tmpdir"
    printf '%s  %sOutput Error%s\n' "$name" "$YELLOW" "$NC"
    return 1
  fi

  if ! clang "$tmp_o" -o "$tmp_bin" -static -L"$LIBDIR" -lsysy_x86 >/dev/null 2>/dev/null; then
    rm -rf "$tmpdir"
    printf '%s  %sLink Error%s\n' "$name" "$YELLOW" "$NC"
    return 1
  fi

  : >"$act_out"
  local rc=0
  if [[ -f "$stdin_file" ]]; then
    timeout "$ASM_TIMEOUT" "$tmp_bin" <"$stdin_file" >"$act_out" 2>/dev/null
    rc=$?
  else
    timeout "$ASM_TIMEOUT" "$tmp_bin" >"$act_out" 2>/dev/null
    rc=$?
  fi

  if [[ $rc -eq 124 ]]; then
    rm -rf "$tmpdir"
    printf '%s  %sExecute Time Limit Exceed%s\n' "$name" "$YELLOW" "$NC"
    return 1
  fi
  if [[ $rc -eq 139 ]]; then
    rm -rf "$tmpdir"
    printf '%s  %sRuntime Error (Segmentation Fault)%s\n' "$name" "$YELLOW" "$NC"
    return 1
  fi

  add_returncode "$act_out" "$rc"

  if diff --strip-trailing-cr -b -q "$act_out" "$std_out" >/dev/null 2>/dev/null; then
    rm -rf "$tmpdir"
    printf '%s  %sAccepted%s\n' "$name" "$GREEN" "$NC"
    return 0
  fi

  rm -rf "$tmpdir"
  printf '%s  %sWrong Answer%s\n' "$name" "$RED" "$NC"
  return 1
}

main() {
  if [[ ! -x "$SYSY" ]]; then
    echo "ERROR: compiler not found or not executable: $SYSY" >&2
    return 2
  fi
  if ! command -v base64 >/dev/null 2>&1; then
    echo "ERROR: base64 not found in PATH" >&2
    return 2
  fi
  if [[ -x "$OPTC_BIN" ]]; then
    rm -f "$OPTC_BIN"
  fi

  extract_optc || return $?
  extract_optcases || return $?

  local total=0
  local passed=0
  local -a passed_names=()
  local -a failed_names=()

  shopt -s nullglob
  for case_dir in "$OPTDIR"/*/; do
    local name
    name="$(basename "$case_dir")"
    if [[ ! -f "${case_dir}/test.sy" || ! -f "${case_dir}/test.out" ]]; then
      continue
    fi
    total=$((total + 1))
    if run_one_case "$case_dir"; then
      passed=$((passed + 1))
      passed_names+=("$name")
    else
      failed_names+=("$name")
    fi
  done

  if [[ ${#passed_names[@]} -gt 0 ]]; then
    printf '\n%s\n' "Passed:"
    for n in "${passed_names[@]}"; do
      printf '  - %s\n' "$n"
    done
  fi
  if [[ ${#failed_names[@]} -gt 0 ]]; then
    printf '\n%s\n' "Failed:"
    for n in "${failed_names[@]}"; do
      printf '  - %s\n' "$n"
    done
  fi

  if [[ -x "$OPTC_BIN" ]]; then
    rm -f "$OPTC_BIN"
  fi
}

main "$@"
exit $?

